import { tags } from 'decantr/tags';
import { createSignal } from 'decantr/state';
import { css } from 'decantr/css';
import { Button, Card, Badge, icon } from 'decantr/components';

code.example:
function TierCard({ tier, onSubscribe, isPopular = false, billingCycle = 'monthly' }) {
  const { div, h3, p, span, ul, li } = tags;
  const price = billingCycle === 'yearly' ? tier.yearlyPrice : tier.monthlyPrice;
  const period = billingCycle === 'yearly' ? '/year' : '/month';

  return Card({ class: css(`studio-card _flex _col _p6 _r3 _trans _hover:shadow ${isPopular ? 'studio-card-premium' : ''}`) },
    isPopular ? Badge({ variant: 'default', class: css('_self[start] _mb3 _bgPrimary') }, 'Most Popular') : null,
    div({ class: css('_mb4') },
      div({ class: css('_flex _aic _gap2 _mb2') },
        div({ class: css('_w3 _h3 _r1'), style: `background:${tier.color || '#F97316'}` }),
        h3({ class: css('_heading4') }, tier.name)
      ),
      p({ class: css('_textsm _fgmuted') }, tier.description)
    ),
    div({ class: css('_flex _aic _gap1 _mb6') },
      span({ class: css('_heading1') }, '$', price),
      span({ class: css('_fgmuted') }, period)
    ),
    ul({ class: css('_flex _col _gap3 _mb6 _flex1') },
      ...tier.benefits.map(benefit =>
        li({ class: css('_flex _aic _gap2') },
          icon('check', { size: '18', class: css('_fgSuccess') }),
          span({ class: css('_textsm') }, benefit)
        )
      )
    ),
    Button({ variant: isPopular ? 'primary' : 'outline', class: css('_wfull studio-glow'), onclick: () => onSubscribe?.(tier) },
      'Subscribe'
    ),
    tier.subscriberCount ? p({ class: css('_textsm _fgmuted _tc _mt3') },
      icon('users', { size: '14', class: css('_mr1') }), tier.subscriberCount, ' subscribers'
    ) : null
  );
}

